package ir.tahamohamadi.blog.post; import ir.tahamohamadi.media.asset.MediaAsset; import jakarta.persistence.*; import lombok.*; import java.util.*;
@Entity @Table(name="blog_post_media") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class BlogPostMedia { @EmbeddedId private BlogPostMediaId id; @ManyToOne(fetch=FetchType.LAZY) @MapsId("blogPostId") @JoinColumn(name="blog_post_id") private BlogPost blogPost; @ManyToOne(fetch=FetchType.LAZY) @MapsId("mediaAssetId") @JoinColumn(name="media_asset_id") private MediaAsset mediaAsset; @Column(name="sort_order",nullable=false) private int sortOrder; private BlogPostMedia(BlogPost post,MediaAsset media,BlogPostMediaUsage usage,int order){if(order<0)throw new IllegalArgumentException("sortOrder must be nonnegative");blogPost=Objects.requireNonNull(post);mediaAsset=Objects.requireNonNull(media);id=new BlogPostMediaId(post.getId(),media.getId(),usage);sortOrder=order;} public static BlogPostMedia attach(BlogPost post,MediaAsset media,BlogPostMediaUsage usage,int order){return new BlogPostMedia(post,media,usage,order);} @Override public boolean equals(Object o){return this==o||(o instanceof BlogPostMedia m&&id.equals(m.id));} @Override public int hashCode(){return id==null?0:id.hashCode();} @Override public String toString(){return "BlogPostMedia{id="+id+", sortOrder="+sortOrder+"}";} }
